    ('ca878e0f-f83f-5004-95c8-89b7378393df', 'consult', '2024-11-06T16:00:00.000Z', 'Initial Overlake musculoskeletal evaluation for worsening left thigh pain', 'Initial Overlake musculoskeletal evaluation documented lateral/anterior left thigh pain with calf cramping, possible L4/L5 concern, reported colder left leg, IT band/patellofemoral considerations, and no allodynia; clinician was not ready to suspect CRPS.', 'Igor Uritskiy MD', 'Overlake Clinics Musculoskeletal Medicine at Highmark', '84cf8f18-552e-5cb0-9947-092f3e279760', null, null, null, null, null, null, null, null, null, null),
    ('758f3bdb-f692-597c-8bdb-b91a5632466d', 'consult', '2024-11-17T12:00:00.000Z', 'Major MVC in Hawaii with polytrauma', 'Extracted digest documents high-impact rollover MVC with small subdural hematoma/brain bleed, C1 fracture, pneumothorax, right sacral fracture, left acetabular fracture, and pelvic ring/ramus fracture. Original left-thigh pain predated this crash, but the crash added major pelvic/lumbosacral/cervical and cognitive confounders.', null, null, '182e9b67-8d39-5a1b-b520-365f58cc1950', null, null, null, null, null, null, null, null, null, null),
