    ('72866232-3e69-5ba4-bec2-9f5422b49ed0', 'consult', '2025-02-24T16:00:00.000Z', 'Visit: Overlake Clinics Musculoskeletal Medicine PT at Highmark', 'Encounter type: Ambulatory. Department: Overlake Clinics Musculoskeletal Medicine PT at Highmark. Reason: Physical Therapy (Routine) - Closed Specialty Diagnoses / Procedures Referred By Contact Referred To Contact Physical Therapy Diagnoses Fracture of pelvis Closed fracture of sacrum, unspecified portion of sacrum, initial. Imported from records_md/generated/healthsummary_xml/DOC0027.md.', 'J Fore PT', 'Overlake Clinics Musculoskeletal Medicine PT at Highmark', 'f2e1fe2d-e5f8-5f17-baad-5b1ca196bd12', null, null, null, null, null, null, null, null, null, null),
    ('449f786d-bdd9-5039-b3d0-3067aeffba26', 'imaging', '2025-02-26T16:20:00.000Z', 'Bladder ultrasound - normal postvoid residual', 'Bladder ultrasound ordered for difficulty emptying bladder. New Data Addendum reports prevoid 388 mL, postvoid 18 mL, and normal sonographic bladder appearance, weakening major urinary retention as support for tethered cord.', 'Irine Vaiman MD', 'Overlake Outpatient Medical Imaging', '5ca88fcd-b8fb-53f1-853a-001756b1279d', null, null, null, null, null, null, null, null, null, null),
    ('27273bac-de8c-5031-9ff6-0c9cbbea8a7a', 'consult', '2025-03-17T15:00:00.000Z', 'Visit: Overlake Clinics Musculoskeletal Medicine at Highmark', 'Encounter type: PR OFFICE/OUTPATIENT ESTABLISHED HIGH MDM 40 MIN. Department: Overlake Clinics Musculoskeletal Medicine at Highmark. Reason: Reason Follow-up. Imported from records_md/generated/healthsummary_xml/DOC0025.md.', 'Igor Uritskiy MD', 'Overlake Clinics Musculoskeletal Medicine at Highmark', 'a703b141-7285-504e-92ab-1a723e60cdd2', null, null, null, null, null, null, null, null, null, null),
    ('cc141d3c-b7b3-5e71-a92b-a6da02073b6f', 'imaging', '2025-03-19T14:59:00.000Z', 'Lumbar MRI with thin filum terminale lipoma and no high-grade stenosis', 'Lumbar MRI showed thin filum terminale lipoma and minimal degenerative changes without high-grade stenosis; this did not strongly support a compressive radiculopathy explanation.', 'Igor Uritskiy MD', 'Overlake Outpatient Medical Imaging', '9d5bf596-d045-5c1f-a900-ad4e4f78a467', null, null, null, null, null, null, null, null, null, null),
    ('caebb14f-0609-5bf1-8a7c-561f10f673ac', 'procedure_test', '2025-03-25T12:00:00.000Z', 'Lumbar sympathetic block / sympathetic procedure', 'Lumbar sympathetic block/procedure inferred from pain follow-up notes and Acute Pain Therapies scans. Response was not cleanly diagnostic.', null, null, '182e9b67-8d39-5a1b-b520-365f58cc1950', 'Would a lumbar sympathetic block produce objective or sustained pain/autonomic improvement supporting sympathetically maintained pain?', null, 'Digest states response was brief/transient at most and not clearly diagnostic; exact injectate, level, temperature change, and pain score remain missing.', null, null, null, null, null, 'unclear', null),
    ('cc1e1bfb-a2fc-5de8-ba73-745e80ca6c0d', 'consult', '2025-04-01T08:45:00.000Z', 'Visit: Proliance Orthopaedics and Sports Medicine Bellevue', 'Encounter type: PR OFFICE/OUTPATIENT ESTABLISHED MOD MDM 30 MIN. Department: Proliance Orthopaedics and Sports Medicine Bellevue. Reason: Reason Follow-up Follow-up. Imported from records_md/generated/healthsummary_xml/DOC0023.md.', 'Silas Marshall MD', 'Proliance Orthopaedics and Sports Medicine Bellevue', '6b2b4f1f-b38b-5780-a6e9-9f2f924df603', null, null, null, null, null, null, null, null, null, null),
    ('01bc4fdc-f484-50ef-93ef-2144390c3042', 'procedure_test', '2025-04-09T12:00:00.000Z', 'Left L5-S1 transforaminal epidural steroid injection', 'Left L5-S1 transforaminal epidural steroid injection for lumbar radiculopathy/lumbosacral radiculitis. Later notes make dominant L5 radiculopathy less likely because the injection did not produce diagnostic relief.', null, null, '182e9b67-8d39-5a1b-b520-365f58cc1950', 'Would left L5-S1 transforaminal epidural steroid injection support a radicular pain generator?', null, 'Operative report reportedly documented no immediate complication; later notes indicate pain escalated/worsened rather than diagnostic relief.', null, null, null, null, null, 'partially', null),
    ('a0498978-9996-5f82-8b8d-41453818c6f0', 'imaging', '2025-04-14T14:08:00.000Z', 'Imaging: Overlake Outpatient Medical Imaging', 'Encounter type: Ambulatory. Department: Overlake Outpatient Medical Imaging. Imported from records_md/generated/healthsummary_xml/DOC0022.md.', 'Irine Vaiman MD', 'Overlake Outpatient Medical Imaging', '867d0490-f822-5c7d-b3f0-b45b28a59536', null, null, null, null, null, null, null, null, null, null),
    ('fd16ed0e-e73e-54d0-986c-59cc453ba706', 'consult', '2025-04-30T02:18:00.000Z', 'Visit: Overlake Emergency Department', 'Encounter type: Emergency. Department: Overlake Emergency Department. Reason: Reason Pain. Imported from records_md/generated/healthsummary_xml/DOC0021.md.', 'Alex Lambert MD', 'Overlake Emergency Department', 'edaf141f-268c-5b7b-a3ab-c11ad25e18d5', null, null, null, null, null, null, null, null, null, null),
    ('081067b4-b163-5ab3-8f29-ba9ae7a16b86', 'consult', '2025-05-02T12:00:00.000Z', 'Kirkland Spine Care follow-up after epidural injection', 'Kirkland Spine Care follow-up described small left L5-S1 HNP/radiculopathy framing, noted the 2025-04-09 lumbar ESI did not improve pain and seemed to exacerbate it, and planned EMG/NCV.', null, null, '182e9b67-8d39-5a1b-b520-365f58cc1950', null, null, null, null, null, null, null, null, null, null),
    ('cc6e4d26-4fdc-5a41-a1ea-702095990478', 'consult', '2025-05-07T10:20:00.000Z', 'Visit: Overlake Clinics Musculoskeletal Medicine at Highmark', 'Encounter type: PR OFFICE/OUTPATIENT ESTABLISHED HIGH MDM 40 MIN. Department: Overlake Clinics Musculoskeletal Medicine at Highmark. Reason: Reason Follow-up. Imported from records_md/generated/healthsummary_xml/DOC0020.md.', 'Igor Uritskiy MD', 'Overlake Clinics Musculoskeletal Medicine at Highmark', '893f5c3f-5be1-5c74-b36d-baa28abf3263', null, null, null, null, null, null, null, null, null, null),
    ('c24ae2cd-7197-5c92-a793-5961fa2740b1', 'consult', '2025-05-08T08:30:00.000Z', 'Visit: Overlake Clinics Musculoskeletal Medicine PT at Highmark', 'Encounter type: Ambulatory. Department: Overlake Clinics Musculoskeletal Medicine PT at Highmark. Reason: Physical Therapy (Routine) - Closed Specialty Diagnoses / Procedures Referred By Contact Referred To Contact Physical Therapy Diagnoses Fracture of pelvis Closed fracture of sacrum, unspecified portion of sacrum, initial. Imported from records_md/generated/healthsummary_xml/DOC0019.md.', 'J Fore PT', 'Overlake Clinics Musculoskeletal Medicine PT at Highmark', '1d3f1f30-4399-5058-8997-9f7d0a55e45d', null, null, null, null, null, null, null, null, null, null),
    ('9e613d22-cc0b-571b-97aa-b484dfb25c94', 'procedure_test', '2025-06-17T12:00:00.000Z', 'EMG/NCV attempt - NCS not tolerated, limited EMG normal', 'Limited electrodiagnostic testing weakens large-fiber motor radiculopathy/plexopathy/myopathy but does not rule out small cutaneous nerve injury, small-fiber pain, or intermittently symptomatic radiculopathy.', null, null, '182e9b67-8d39-5a1b-b520-365f58cc1950', 'Was there large-fiber evidence of lumbar radiculopathy, sacral plexopathy, or myopathy?', null, 'Nerve conduction study was not tolerated and was terminated; limited EMG portion reportedly showed no denervation and no evidence of lumbar radiculopathy, sacral plexopathy, or myopathy.', null, null, null, null, null, 'partially', null),
    ('c9321a58-f5ac-5605-8e8d-2292ca870a8d', 'consult', '2025-07-09T11:00:00.000Z', 'Overlake follow-up: blocks/epidural not diagnostically helpful', 'Overlake musculoskeletal follow-up noted EMG/NCS limitations, sympathetic ganglion blocks and L5 transforaminal epidural injection not diagnostically helpful, presentation not classic CRPS, and recommendation for corticosteroid-based LFCN block.', 'Igor Uritskiy MD', 'Overlake Clinics Musculoskeletal Medicine at Highmark', '23c41106-9c7e-584b-a43d-627022feca1a', null, null, null, null, null, null, null, null, null, null),
    ('ef65e451-ff1b-5cd0-b997-c740a721e8a7', 'consult', '2025-07-22T14:45:00.000Z', 'Visit: Overlake Neuroscience Institute - Neurology', 'Encounter type: PR OFFICE/OUTPATIENT NEW MODERATE MDM 45 MINUTES. Department: Overlake Neuroscience Institute - Neurology. Reason: Reason Consultation Neurology (Routine) - Closed Specialty Diagnoses / Procedures Referred By Contact Referred To Contact Neurology Diagnoses Difficulty in urination Irine Vaiman, MD 2007 152ND AVE NE REDMOND, WA 98052 P. Imported from records_md/generated/healthsummary_xml/DOC0017.md.', 'Zachary Robateau MD', 'Overlake Neuroscience Institute - Neurology', 'f40bf869-321d-56e0-bf52-0a9bef053fb4', null, null, null, null, null, null, null, null, null, null),
    ('b78a3939-4442-57f2-9890-b6b163ff7feb', 'consult', '2025-07-30T13:30:00.000Z', 'Visit: Overlake Neuroscience Institute - Neuropsychology', 'Encounter type: Ambulatory. Department: Overlake Neuroscience Institute - Neuropsychology. Reason: Psychiatric (Routine) - Authorized Specialty Diagnoses / Procedures Referred By Contact Referred To Contact Psychology Diagnoses Memory loss Zachary R Robateau, MD Phone: tel:+1-206-320-3494 fax:+1-206-386-2845 Overlake. Imported from records_md/generated/healthsummary_xml/DOC0015.md.', 'Lindsay Kraemer', 'Overlake Neuroscience Institute - Neuropsychology', 'f6dc5f65-830e-5f85-b172-ff9f4f09ee1e', null, null, null, null, null, null, null, null, null, null),
    ('2e2d2dd8-5339-5f5e-be9b-bd28d87cff26', 'procedure_test', '2025-07-30T15:30:00.000Z', 'Left LFCN steroid block - lidocaine plus Kenalog', 'Second LFCN perineural injection with lidocaine and Kenalog. Later notes report initial nocturnal pain increase and intermittent partial relief, but not a clean diagnostic response.', 'Amos Song MD', 'Overlake Clinics Musculoskeletal Medicine', '0600b729-0172-5757-98ef-e971f0131f84', 'Would left lateral femoral cutaneous nerve steroid/anesthetic injection produce a clinically meaningful diagnostic or therapeutic response?', 'Repeat LFCN block was recommended after prior anesthetic-only block was nondiagnostic.', 'Procedure note reports ultrasound-guided left LFCN perineural injection with 1 mL 1% lidocaine plus 1 mL/40 mg Kenalog and no paresthesias or pain elicited during injection.', null, null, null, null, null, 'partially', null),
    ('75da78b2-7d4c-5a56-933b-0a76b6ce51fe', 'consult', '2025-09-04T06:50:00.000Z', 'Visit: Overlake Emergency Department', 'Encounter type: Emergency. Department: Overlake Emergency Department. Reason: Reason Finger Injury. Imported from records_md/generated/healthsummary_xml/DOC0014.md.', 'Dana Hirsch MD', 'Overlake Emergency Department', '6c924bcd-8bcb-5125-b990-b1a6ef1ab2f3', null, null, null, null, null, null, null, null, null, null),
    ('f27c6020-46f7-52be-ae1f-5125fbd2005a', 'consult', '2025-09-15T09:40:00.000Z', 'Overlake follow-up: LFCN block not diagnostic, ketamine partial/temporary', 'Follow-up after LFCN steroid block and ketamine infusions. New Data Addendum reports LFCN block initially increased nocturnal pain, then gave intermittent about 30% relief; clinician wrote LFCN block had not produced a diagnostic response.', 'Igor Uritskiy MD', 'Overlake Clinics Musculoskeletal Medicine at Highmark', 'd309a572-542d-568d-ba8a-c4a86d3f09ca', null, null, null, null, null, null, null, null, null, null),
    ('3794cc57-9dc1-52f2-85cb-f23c076d5e7e', 'consult', '2025-09-16T09:00:00.000Z', 'Visit: Overlake Neuroscience Institute - Neuropsychology', 'Encounter type: Ambulatory. Department: Overlake Neuroscience Institute - Neuropsychology. Reason: Psychiatric (Routine) - Authorized Specialty Diagnoses / Procedures Referred By Contact Referred To Contact Psychology Diagnoses Memory loss Zachary R Robateau, MD Phone: tel:+1-206-320-3494 fax:+1-206-386-2845 Overlake. Imported from records_md/generated/healthsummary_xml/DOC0012.md.', 'Lindsay Kraemer', 'Overlake Neuroscience Institute - Neuropsychology', '081ff9e9-c2a7-55ad-bbc7-a1be7683af5e', null, null, null, null, null, null, null, null, null, null),
    ('d029ad8d-0ccb-5010-9d7e-9df793a23dd8', 'consult', '2025-09-29T12:00:00.000Z', 'Stanford initial pain consultation - Tawfik', 'Initial Stanford pain consultation. Impression included left thigh pain after stab wound, possible scar neuroma versus lateral femoral cutaneous nerve injury. Exam documented well-healed scar, intact pinprick/light touch, no allodynia, and 5/5 strength. Recommended MR neurography, scar injection, possible later LFCN block, pain psychology/PT, and medication risk mitigation.', 'Vivianne Lily Tawfik, MD', 'Stanford Pain Management Center', '7cfb90d7-45bd-5fe1-a284-41df92792e2d', null, null, null, null, null, null, null, null, null, null),
    ('0a592294-441c-5d97-9cda-3accb960ccfb', 'imaging', '2025-10-01T12:00:00.000Z', 'Stanford left thigh MR neurography', '3T left thigh MR neurography. Stanford report and local DICOM review found no discrete neuroma, perineural mass, nerve discontinuity, neural impingement, abscess, hematoma, acute fracture, or convincing major named nerve abnormality; this does not rule out tiny terminal cutaneous branch neuroma or dynamic scar tethering.', null, null, 'af62cd40-a191-5cf1-8e4f-3cc78f102fbf', null, null, null, null, null, null, null, null, null, null),
    ('3ad260d0-416a-53f7-8d1d-86e52724e828', 'consult', '2025-10-09T13:00:00.000Z', 'Visit: Overlake Neuroscience Institute - Neuropsychology', 'Encounter type: Ambulatory. Department: Overlake Neuroscience Institute - Neuropsychology. Imported from records_md/generated/healthsummary_xml/DOC0011.md.', 'Lindsay Kraemer', 'Overlake Neuroscience Institute - Neuropsychology', 'd204d85d-f328-5b45-b154-051c5d00817a', null, null, null, null, null, null, null, null, null, null),
    ('64414639-602e-5663-be53-c796852920db', 'procedure_test', '2025-10-17T22:45:00.000Z', 'Stanford left thigh scar injection - Qian', 'Scar injection into left thigh scar using 0.5% ropivacaine, 2 mL. Immediate pain score did not improve; later notes describe a significant delayed flare and eventual partial change in pain intensity/localization.', 'Xiang Qian, MD, PhD', 'Stanford Pain Management', 'e42980ba-8f5d-5253-81fe-d0243c205b3b', 'Would superficial left thigh scar injection reduce the usual scar/thigh pain and help localize a scar-mediated pain generator?', 'Pre-procedure NRS: 8/10.', 'Post-procedure NRS: 8/10. Source note states the procedure did not help pain yet.', null, null, null, null, 'Patient voiced concern for possible post-procedure pain flare; later Stanford follow-up describes significant delayed flare, bulge/red circle concern, leg shaking, buckling sensation, and later reduction in pain intensity.', 'partially', null),
    ('17830c35-b05f-53d0-a523-26573af27496', 'consult', '2025-10-24T11:40:00.000Z', 'Visit: Overlake Clinics Musculoskeletal Medicine at Highmark', 'Encounter type: PR OFFICE/OUTPATIENT ESTABLISHED HIGH MDM 40 MIN. Department: Overlake Clinics Musculoskeletal Medicine at Highmark. Reason: Reason Follow-up. Imported from records_md/generated/healthsummary_xml/DOC0010.md.', 'Igor Uritskiy MD', 'Overlake Clinics Musculoskeletal Medicine at Highmark', 'a9120aee-2943-57d6-bb86-4e957830b01b', null, null, null, null, null, null, null, null, null, null),
    ('5b5fb82b-06d5-5b19-be16-0dbd0ca96713', 'consult', '2025-10-27T11:00:00.000Z', 'Visit: Overlake Neuroscience Institute - Neuropsychology', 'Encounter type: Ambulatory. Department: Overlake Neuroscience Institute - Neuropsychology. Imported from records_md/generated/healthsummary_xml/DOC0009.md.', 'Lindsay Kraemer', 'Overlake Neuroscience Institute - Neuropsychology', '79f2d783-e206-5c0a-87bd-13f7b0879a25', null, null, null, null, null, null, null, null, null, null),
    ('eb6e74f2-b4fe-5c9c-a751-ec6a1e098ff4', 'imaging', '2025-10-29T12:00:00.000Z', 'Outside ultrasound after scar injection flare', 'Outside ultrasound reportedly showed heterogeneously echogenic subcutaneous tissue and similar irregular echogenicity in the underlying vastus lateralis near the painful left lateral thigh scar, without drainable collection or hypervascularity; LFCN branches were difficult to visualize.', null, null, 'c6bfe76c-5269-5a38-8b60-211aa64f0a03', null, null, null, null, null, null, null, null, null, null),
    ('19c5b1d2-d253-50b0-b947-cda997b73e92', 'imaging', '2025-11-06T15:20:00.000Z', 'Imaging: Overlake Medical Imaging', 'Encounter type: Ambulatory. Department: Overlake Medical Imaging. Imported from records_md/generated/healthsummary_xml/DOC0008.md.', 'Irine Vaiman MD', 'Overlake Medical Imaging', '70110b08-628d-5da7-a71d-01d26cbcd60d', null, null, null, null, null, null, null, null, null, null),
    ('fc8c6b71-f773-5198-bf92-305e2243e83d', 'consult', '2025-11-17T12:00:00.000Z', 'Stanford pain follow-up / peripheral nerve team review', 'Follow-up after 2025-10-17 scar injection. Patient reported significant delayed pain flare, LFCN blocks caused numbness without pain relief, and peripheral nerve team reviewed MR neurogram with no MRN findings; recommendations included scar injection as scheduled, possible LFCN block, and scar exploration if appropriate.', 'Vivianne Lily Tawfik, MD', 'Stanford Pain Management Center', '41e904b7-5e74-5f3f-ba6d-9c2554e70981', null, null, null, null, null, null, null, null, null, null),
    ('31553dc8-bc02-5ff6-ba62-0b91f911769d', 'consult', '2025-12-04T04:56:00.000Z', 'Visit: Overlake Emergency Department', 'Encounter type: Emergency. Department: Overlake Emergency Department. Reason: Reason visual disturbance Tachycardia. Imported from records_md/generated/healthsummary_xml/DOC0007.md.', 'Alex Lambert MD', 'Overlake Emergency Department', '05242b01-3215-5798-b1a0-5f81e28f7cfb', null, null, null, null, null, null, null, null, null, null),
    ('98202173-fccf-5162-aa4d-a410fd3dc968', 'procedure_test', '2025-12-23T12:00:00.000Z', 'Deep scar injection / hydrodissection targeting branch to vastus lateralis', 'Deep scar injection/hydrodissection into the left lateral thigh scar, target described as branch of nerve to vastus lateralis. Not a clean diagnostic success and may have changed symptom distribution.', null, null, '72dc67e5-c76d-55fd-abe9-a18494463adf', 'Would deep scar hydrodissection targeting a branch to vastus lateralis improve pain or clarify the local generator?', null, 'Patient did not recall numbness or pain improvement; noted left foot numbness. Later Stanford interpretation suggested possible narrowing toward scar area but not a clean diagnostic success.', null, null, null, null, 'Top-of-foot/left foot numbness was reported after the procedure and requires separate localization because it does not fit isolated LFCN distribution.', 'partially', null),
    ('c494651b-0f21-5164-b5a1-bfa4761c11c3', 'consult', '2026-01-26T22:30:00.000Z', 'Stanford pain follow-up after 2025-12-23 hydrodissection', 'Stanford pain follow-up documented 2025-12-23 deep scar injection/hydrodissection with no recalled numbness or pain improvement, new left foot numbness, possible pain localization toward scar, medication trials, prior blocks, and continued concern for scar neuroma/LFCN/anterior femoral cutaneous/vastus lateralis scar mechanisms.', 'Vivianne Lily Tawfik, MD', 'Stanford Pain Management Center', '72dc67e5-c76d-55fd-abe9-a18494463adf', null, null, null, null, null, null, null, null, null, null),
    ('953ffa0e-778c-5052-b8a3-9f447718fa1f', 'consult', '2026-02-02T12:00:00.000Z', 'Stanford pain psychology evaluation', 'Pain psychology consultation for neuropathic left thigh pain and psychosocial contributors/treatment recommendations. Source should be used as behavioral-health context rather than an anatomic localization event.', 'Stanford Pain Psychology', 'Stanford Pain Management Center', '84ad7dde-6594-5cf1-93a7-ff1e2f111a20', null, null, null, null, null, null, null, null, null, null),
    ('0ed5b1f1-6367-5178-a2e7-c580299b0fdc', 'consult', '2026-02-09T12:00:00.000Z', 'Stanford pain follow-up - hold further procedures pending better localization', 'Stanford pain follow-up expanded differential to scar neuroma, LFCN injury, anterior femoral cutaneous nerve injury, or vastus lateralis muscle scarring. Recommended holding off further procedures, considering sigma-1 PET study before exploratory surgery, pain psychology/PT, and cautious medication management.', 'Samantha Chevel O''Connor Campbell, MD / Vivianne Lily Tawfik, MD', 'Stanford Pain Management Center', 'ea4d466a-d824-5563-b50f-d59dce8bcbe2', null, null, null, null, null, null, null, null, null, null),
    ('599c5feb-2bfd-53da-a65a-68a49b667ee7', 'consult', '2026-02-09T20:00:00.000Z', 'Stanford hand/plastic surgery consult - scar exploration/RPNI discussed', 'Surgical consult for painful left leg scar. Scar exploration and possible RPNI were discussed if an eligible nerve was identified; note emphasized no clear large nerve target and risk that surgery might not help or might worsen pain.', 'Paige McCarthy Fox, MD, PhD', 'Stanford Hand Surgery Clinic', 'c6bfe76c-5269-5a38-8b60-211aa64f0a03', 'Was there a sufficiently targetable scar/nerve lesion to justify scar exploration and possible RPNI?', 'Persistent 8-9/10 pain centralized to left thigh scar with radiation through the leg; no clearly identified large target nerve on imaging/injection.', 'Surgery risks/benefits discussed; patient elected to move forward at that time, but surgeon emphasized uncertainty and possible worsening.', null, null, null, null, null, 'partially', null),
    ('2c218acd-523c-548d-9f30-253d8f72af46', 'consult', '2026-02-11T11:20:00.000Z', 'Overlake follow-up after Stanford scar hydrodissection', 'Overlake musculoskeletal follow-up documented that hydrodissection of sensory nerves around scar tissue reportedly did not improve symptoms; pain remained severe and radicular-sounding but prior epidural approach had worsened symptoms.', 'Igor Uritskiy MD', 'Overlake Clinics Musculoskeletal Medicine at Highmark', '039424a8-596b-5d2f-ab59-de73a0581084', null, null, null, null, null, null, null, null, null, null),
    ('7bd04f1d-b905-58e3-9f62-dfcfa4f1c3ae', 'consult', '2026-03-22T21:56:00.000Z', 'Overlake ED / brief admission for worsening bilateral leg pain', 'Presented with worsening left leg pain and new right leg pain. ED used Stanford-style flare medications including IV hydromorphone, lorazepam, and ketamine with minimal improvement; admission was planned but patient left against medical advice before inpatient reassessment.', 'Bradford Kilcline MD', 'Overlake Emergency Department', '90e320f5-c5c7-5589-820f-51bf9e728e8e', null, null, null, null, null, null, null, null, null, null),
    ('379302a1-8db2-5a76-8ac4-1827af3d5ca9', 'consult', '2026-04-03T05:01:00.000Z', 'Overlake inpatient pain admission labeled CRPS/RSD', 'Admitted for acute-on-chronic pain labeled CRPS/reflex sympathetic dystrophy. Pain reportedly progressed to right leg and right arm; inpatient plan transitioned from oxycodone to oral hydromorphone and used short courses of prednisone/clonazepam on discharge.', 'Gregory Bennett MD', 'Overlake Cardiac/Stroke/Telemetry Unit, Bldg. 1 South, 4th Floor', 'ebd49cfc-5b10-546c-9d7e-f606603af280', null, null, null, null, null, null, null, null, null, null),
    ('4fcc1e15-fa72-563d-8144-e67c395cf040', 'consult', '2026-04-09T19:29:00.000Z', 'Stanford anesthesia preprocedure evaluation for planned left leg scar surgery', 'Pre-anesthesia evaluation for planned 2026-04-16 lower extremity wound closure for painful scar. Note listed chronic pain/CRPS diagnoses, medication list, and procedure-flare considerations. Later patient update says the procedure did not happen.', 'Richard D Muico, NP', 'Stanford Anesthesia Preprocedure Evaluation', '762fcc25-94e6-5852-b372-1995c1b890b9', 'What question was this procedure or test intended to answer, and did it change symptoms or management?', null, null, null, null, null, null, null, 'unclear', null),
    ('32974fd7-5652-50bb-b6c5-3b903c519c0a', 'consult', '2026-04-13T17:30:00.000Z', 'Stanford surgery follow-up - scar surgery deferred/canceled during flare', 'Surgery follow-up documented worsening CRPS symptoms with spread to other leg and hand. Patient was not amenable to proceeding with surgery; plan was to cancel the scheduled surgery and follow up by video.', 'Paige McCarthy Fox, MD, PhD', 'Stanford Hand Surgery Clinic', '2af34a64-5047-52bc-8afd-244c53bdc79b', 'What question was this procedure or test intended to answer, and did it change symptoms or management?', null, null, null, null, null, null, null, 'unclear', null),
    ('9a87726e-f278-5e2b-963e-4d6a78d2d548', 'consult', '2026-05-01T11:00:00.000Z', 'Overlake neurology follow-up for weakness, vision, memory, gait', 'Neurology follow-up for worsening weakness, visual disturbance, memory loss, hesitant speech, and slow unsteady gait in the setting of pain flare and prior trauma; brain MRI and speech therapy were ordered.', 'Olav Jaren MD', 'Overlake Neuroscience Institute - Neurology', '7c2a17cb-825d-5534-8fbb-543c91668832', null, null, null, null, null, null, null, null, null, null);

  insert into public.events (
    id,
    family_id,
    user_id,
    type,
    occurred_at,
    ended_at,
    title,
    summary,
    provider,
    location,
    source_id,
    diagnostic_question,
    baseline_before,
    immediate_effect,
    effect_24h,
    effect_72h,
    effect_1w,
    effect_1m,
    new_symptoms,
    answered_question,
    repeat_recommendation,
    created_at,
    updated_at
  )
  select
    imported_event.import_id,
    import_family_id,
    import_user_id,
    imported_event.type,
    imported_event.occurred_at,
    null,
    imported_event.title,
    imported_event.summary,
    imported_event.provider,
    imported_event.location,
    source_map.source_id,
    imported_event.diagnostic_question,
    imported_event.baseline_before,
    imported_event.immediate_effect,
    imported_event.effect_24h,
    imported_event.effect_72h,
    imported_event.effect_1w,
    imported_event.effect_1m,
    imported_event.new_symptoms,
    imported_event.answered_question,
    imported_event.repeat_recommendation,
    now(),
    now()
  from bootstrap_import_events imported_event
  join bootstrap_import_source_map source_map
    on source_map.import_id = imported_event.source_import_id
  on conflict (id) do update set
    type = excluded.type,
    occurred_at = excluded.occurred_at,
    ended_at = excluded.ended_at,
    title = excluded.title,
    summary = excluded.summary,
    provider = excluded.provider,
    location = excluded.location,
    source_id = excluded.source_id,
    diagnostic_question = excluded.diagnostic_question,
    baseline_before = excluded.baseline_before,
    immediate_effect = excluded.immediate_effect,
    effect_24h = excluded.effect_24h,
    effect_72h = excluded.effect_72h,
    effect_1w = excluded.effect_1w,
    effect_1m = excluded.effect_1m,
    new_symptoms = excluded.new_symptoms,
    answered_question = excluded.answered_question,
    repeat_recommendation = excluded.repeat_recommendation,
    updated_at = now(),
    deleted_at = null;

end $$;
